use std::path::Path;
use std::time::{Duration, Instant};

struct FileWatcher {
    path: std::path::PathBuf,
}

impl FileWatcher {
    fn new(path: impl AsRef<Path>) -> Self {
        FileWatcher { path: path.as_ref().to_owned() }
    }

    fn watch(&self) -> Result<(), Box<dyn std::error::Error>> {
        let start = Instant::now();
        loop {
            std::thread::sleep(Duration::from_millis(500));
            match self.check_for_changes(start)? {
                true => println!("File change detected on: {}", self.path.display()),
                false => {},
            }
        }
    }

    fn check_for_changes(&self, start: Instant) -> Result<bool, std::io::Error> {
        let metadata = std::fs::metadata(&self.path)?;
        let _current_modified = metadata.modified()?;

        if start.elapsed() > Duration::from_secs(1) { 
            Ok(true)
        } else {
            Ok(false)
        }
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let path_to_watch = "./config.txt";
    if !Path::new(path_to_watch).exists() {
        std::fs::write(path_to_watch, "Initial content.")?;
    }

    let watcher = FileWatcher::new(path_to_watch);
    println!("Monitoring file changes for: {}", path_to_watch);
    match watcher.watch() {
        Ok(_) => Ok(()),
        Err(e) => { 
            eprintln!("Failed to watch file: {}", e);
            Err(e)
        }
    }
}

use std::fs;
use std::path::Path;
use std::time::Duration;
use std::thread;
use std::io::{self, Write};

struct ConfigWatcher {
    path: String,
}

impl ConfigWatcher {
    fn new(path: &str) -> Self {
        ConfigWatcher {
            path: path.to_string(),
        }
    }

    fn watch(&self) -> io::Result<()> {
        let mut last_modified = fs::metadata(&self.path)?.modified()?;
        println!("Starting watch loop for file: {}", self.path);
        loop {
            thread::sleep(Duration::from_secs(2));
            match fs::metadata(&self.path) {
                Ok(metadata) => {
                    let current_modified = metadata.modified()?;
                    if current_modified > last_modified {
                        println!("n=========================================");
                        println!("File changed detected! Re-running logic...");
                        self.on_config_changed();
                        last_modified = current_modified;
                        println!("Logic update complete.n=========================================n");
                    }
                }
                Err(e) => {
                    eprintln!("Error reading metadata: {}", e);
                    return Err(e);
                }
            }
        }
    }

    fn on_config_changed(&self) {
        println!("Executing mod update routine based on new config state.");

        if let Ok(data) = fs::read_to_string(&self.path) {
            let line_count = data.lines().count();
            println!("Successfully read file content. Found {} lines to process.", line_count);
        } else {
            eprintln!("Could not read file for re-initialization check.");
        }
    }
}
